import React, { useState, useEffect } from 'react';
import axios from 'axios';
import Sidebar from '../components/Sidebar';
import './Pages.css';
// ✅ (OPTIONAL BEST PRACTICE)
import { useNavigate } from 'react-router-dom';

const KatthaAccounts = () => {
  const [language, setLanguage] = useState('en');
  const [accounts, setAccounts] = useState([]);
  const [loading, setLoading] = useState(true);

  // ✅ Navigation (better than window.location)
  const navigate = useNavigate();

  const translations = {
    en: { katthaAccounts: 'Kattha Accounts', balance: 'Balance', lastPurchase: 'Last Purchase', 
      status: 'Status', noData: 'No accounts' },
    te: { katthaAccounts: 'ఖత్తా ఖాతాలు', balance: 'బ్యాలెన్స్', lastPurchase: 'చివరి కొనుగోలు', 
      status: 'స్థితి', noData: 'ఖాతాలు లేవు' },
    hi: { katthaAccounts: 'खता खाते', balance: 'शेष', lastPurchase: 'अंतिम खरीद', 
      status: 'स्थिति', noData: 'कोई खाता नहीं' }
  };

  const t = translations[language] || translations.en;

  useEffect(() => {
    fetchAccounts();
  }, []);

  // ✅ FETCH ACCOUNTS
  const fetchAccounts = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get('http://localhost:5000/api/accounts/pending', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setAccounts(response.data.accounts || []);
    } catch (err) {
      console.error('Error:', err);
    } finally {
      setLoading(false);
    }
  };

  // ✅ DELETE ACCOUNT
  const handleDelete = async (id) => {
    const confirmDelete = window.confirm("Are you sure you want to delete?");
    if (!confirmDelete) return;

    try {
      const token = localStorage.getItem('token');
      await axios.delete(`http://localhost:5000/api/accounts/${id}`, {
        headers: { Authorization: `Bearer ${token}` }
      });

      // Refresh data after delete
      fetchAccounts();

    } catch (err) {
      console.error(err);
    }
  };

  // ✅ EDIT ACCOUNT
  const handleEdit = (id) => {
    navigate(`/edit-account/${id}`);
    // OR (if not using router)
    // window.location.href = `/edit-account/${id}`;
  };

  return (
    <div className="dashboard-layout">
      <Sidebar language={language} />

      <div className="main-content">
        <div className="top-bar">
          <h1>{t.katthaAccounts}</h1>

          <select 
            value={language} 
            onChange={(e) => setLanguage(e.target.value)} 
            className="language-selector"
          >
            <option value="en">English</option>
            <option value="te">Telugu</option>
            <option value="hi">Hindi</option>
          </select>
        </div>

        <div className="page-card">
          {loading ? (
            <p>Loading...</p>
          ) : accounts.length === 0 ? (
            <p className="no-data">{t.noData}</p>
          ) : (
            <table className="bills-table">
              <thead>
                <tr>
                  <th>Customer</th>
                  <th>{t.balance}</th>
                  <th>{t.lastPurchase}</th>
                  <th>{t.status}</th>
                  <th>Action</th> {/* ✅ NEW */}
                </tr>
              </thead>

              <tbody>
                {accounts.map(account => (
                  <tr key={account._id}>
                    <td>{account.customerName}</td>
                    <td>₹ {account.pendingBalance?.toFixed(2)}</td>
                    <td>
                      {account.lastPurchaseDate 
                        ? new Date(account.lastPurchaseDate).toLocaleDateString() 
                        : 'N/A'}
                    </td>

                    <td>
                      <span className="status open">OPEN</span>
                    </td>

                    {/* ✅ ACTION BUTTONS */}
                    <td>
                      <button
                        onClick={() => handleEdit(account._id)}
                        style={{
                          marginRight: '8px',
                          padding: '5px 10px',
                          background: '#FF9800',
                          color: '#fff',
                          border: 'none',
                          borderRadius: '4px',
                          cursor: 'pointer'
                        }}
                      >
                        ✏️ Edit
                      </button>

                      <button
                        onClick={() => handleDelete(account._id)}
                        style={{
                          padding: '5px 10px',
                          background: '#f44336',
                          color: '#fff',
                          border: 'none',
                          borderRadius: '4px',
                          cursor: 'pointer'
                        }}
                      >
                        🗑️ Delete
                      </button>
                    </td>

                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
};

export default KatthaAccounts;
